#include<cstdio>
#include<iostream>
#include<algorithm>
using namespace std;
int a[1005], C[5000][5000];

const int M = 1e9 + 7;

int main(){
	for(int i = 0; i <= 2000; i++)
	{
		C[i][0] = 1;
		for(int j = 1; j <= i; j++)
		{
			C[i][j] = C[i - 1][j - 1] + C[i - 1][j];
			C[i][j] %= M;
		}
	}
	int t;
	cin >> t;
	while(t--)
	{
		int n, m, t = 0;
		cin >> n >> m;
		for(int i = 1; i <= m; i++)
		{
			cin >> a[i];
			t += a[i];
		}
		if(t > n) n++;
		long long ans = 1;
    	for(int i = 1; i <= m; i++)
		{
			ans *= C[n][a[i]];
    		ans %= M;
    		n -= a[i];
    	}
    	cout << ans << endl;	
	}
	return 0;
}
